def discover(self) -> List[Migration]:
    """Find all migration files sorted by version."""
    migrations = []
    for path in sorted(self.migrations_dir.glob("*.py")):
        parts = path.stem.split("_", 1)
        if len(parts) == 2:
            migrations.append(Migration(
                version=parts[0], name=parts[1], path=path
            ))
    return migrations

def get_applied(self) -> set:
    """Get set of applied migration versions."""
    rows = self.conn.execute(
        "SELECT version FROM schema_migrations"
    ).fetchall()
    return {row[0] for row in rows}

def run_pending(self) -> List[str]:
    """Run all pending migrations. Returns list of applied versions."""
    applied = self.get_applied()
    pending = [m for m in self.discover() if m.version not in applied]
    results = []
    for migration in pending:
        module = self._load_module(migration)
        module.up(self.conn)
        self.conn.execute(
            "INSERT INTO schema_migrations (version, applied_at) VALUES (?, ?)",
            (migration.version, datetime.now().isoformat()),
        )
        self.conn.commit()
        results.append(migration.version)
    return results

def _load_module(self, migration: Migration):
    spec = importlib.util.spec_from_file_location(
        f"migration_{migration.version}", migration.path
    )
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    return module

